"use client";
import Link from "next/link";
import { useState } from "react";
import { ArrowRight, Moon, Sun, Scan, Target, PieChart } from "lucide-react";

export default function LandingPage() {
  const [isDarkMode, setIsDarkMode] = useState(true);

  return (
    <div className={`min-h-screen transition-colors duration-300 font-sans ${isDarkMode ? "bg-[#050505] text-white" : "bg-white text-slate-900"}`}>
      {/* 1. NAVBAR (Ultra Minimalist) */}
      <nav className="max-w-6xl mx-auto px-6 py-10 flex justify-between items-center border-b border-slate-200/10">
        <div className="flex items-center gap-3">
          <img src="/logos/cashmap.svg" alt="Logo" className="w-8 h-8 filter grayscale" />
          <span className="text-xl font-bold tracking-tight italic">CASHMAP</span>
        </div>
        
        <div className="flex items-center gap-6">
          <button onClick={() => setIsDarkMode(!isDarkMode)} className="opacity-50 hover:opacity-100 transition-opacity">
            {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
          </button>
          <Link href="/login" className="text-sm font-bold border-b border-current pb-1 hover:text-blue-500 transition-colors">
            LOG IN
          </Link>
        </div>
      </nav>

      {/* 2. HERO SECTION (Blueprint Style) */}
      <main className="max-w-6xl mx-auto px-6 pt-24 pb-32">
        <div className="grid grid-cols-1 md:grid-cols-12 gap-12 items-start">
          
          <div className="md:col-span-8">
            <h1 className="text-7xl md:text-[120px] font-bold leading-[0.8] tracking-tighter mb-12">
              TRACK <br />
              <span className="text-blue-600">SMARTER.</span>
            </h1>
            <p className="max-w-md text-lg md:text-xl font-medium opacity-60 leading-tight">
              Satu tempat untuk memetakan ke mana uangmu pergi. Tanpa ribet, tanpa istilah teknis yang memusingkan.
            </p>
          </div>

          <div className="md:col-span-4 pt-4 flex flex-col gap-8">
            <div className="p-1 border border-blue-600/30 rounded-full inline-block w-fit">
              <Link href="/register" className="bg-blue-600 text-white px-8 py-4 rounded-full font-bold flex items-center gap-2 hover:bg-blue-700 transition-all">
                Daftar Sekarang <ArrowRight size={20} />
              </Link>
            </div>
            <div className="text-[10px] font-mono opacity-40 leading-relaxed uppercase tracking-[0.2em]">
              Built for precision. <br /> Designed for simplicity. <br /> © 2026 CashMap System
            </div>
          </div>

        </div>

        {/* 3. FEATURE SECTION (Modular/Blueprint) */}
        <div className="grid grid-cols-1 md:grid-cols-3 mt-40 border-t border-current/10">
          <div className="py-12 md:pr-12 border-b md:border-b-0 md:border-r border-current/10">
            <Scan size={32} className="mb-6 text-blue-600" />
            <h3 className="text-2xl font-bold mb-4">Pemetaan Otomatis</h3>
            <p className="opacity-50 text-sm leading-relaxed text-justify">
              Langsung lihat pengeluaran terbesarmu tanpa harus menghitung manual. Kami yang urus kalkulasinya, kamu tinggal lihat hasilnya.
            </p>
          </div>
          
          <div className="py-12 md:px-12 border-b md:border-b-0 md:border-r border-current/10">
            <Target size={32} className="mb-6 text-blue-600" />
            <h3 className="text-2xl font-bold mb-4">Fokus 20/80</h3>
            <p className="opacity-50 text-sm leading-relaxed text-justify">
              Cari tahu 20% kebiasaan belanja yang paling banyak menghabiskan saldo bulananmu. Fokus pada apa yang penting.
            </p>
          </div>

          <div className="py-12 md:pl-12">
            <PieChart size={32} className="mb-6 text-blue-600" />
            <h3 className="text-2xl font-bold mb-4">Multi-Akun</h3>
            <p className="opacity-50 text-sm leading-relaxed text-justify">
              Hubungkan semua dompet digital, bank, dan uang tunai dalam satu peta besar. Pantau segalanya dari satu layar.
            </p>
          </div>
        </div>
      </main>
    </div>
  );
}